package com.example.note_todo_app.service

import com.example.note_todo_app.data.model.Todo
import java.util.*

/**
 * Service class that extracts and suggests todos from text content
 */
class TodoSuggester {
    
    /**
     * Extracts candidate todos from the given text using pattern matching
     */
    fun extractCandidateTodos(text: String): List<Todo> {
        val candidates = mutableListOf<Todo>()
        val lines = text.lines()
        
        // Define patterns for different types of todo expressions
        val todoPatterns = listOf(
            Regex("""(?:需要|要|计划)\s*(?:完成|做|处理|准备|购买|安排).*?(?=[:：,\n]|$)"""),  // "需要完成...", "要做..."
            Regex("""(?:提醒|记得|别忘了)\s*.+?(?=[:：,\n]|$)"""),                           // "提醒做...", "记得..."
            Regex("""明天|后天|下周|下个月\s*.*?(?:开会|提交|完成|买|去|办理|预约).*?(?=[:：,\n]|$)"""), // Time + action
            Regex("""截止到?\s*\S{0,10}\s*(?:年|月|日)?\s*.*?(?:提交|完成|交付|上报|支付).*?(?=[:：,\n]|$)"""), // Deadline + task
            Regex("""(?!.*(?:已完成|已做完|done|finished))(\b[A-Za-z]+\s+(?:to|that|which|who)\s+.+?)""")       // "Need to do...", "Want to go..." (English)
        )
        
        for ((index, line) in lines.withIndex()) {
            var matched = false
            
            for (pattern in todoPatterns) {
                val matches = pattern.findAll(line)
                
                for (match in matches) {
                    val todoText = match.value.trim()
                    
                    // Determine priority based on urgency indicators
                    val priority = determinePriority(todoText)
                    
                    // Extract due date if mentioned
                    val dueDate = extractDueDate(todoText)
                    
                    candidates.add(Todo(
                        id = UUID.randomUUID().toString(),
                        title = cleanTodoTitle(todoText),
                        description = "",
                        isCompleted = false,
                        priority = priority,
                        dueDate = dueDate,
                        createdAt = Date(),
                        updatedAt = Date(),
                        noteId = "" // Will be set when associated with a note
                    ))
                    
                    matched = true
                }
            }
            
            // If no specific pattern matched but the line looks like a task, add it anyway
            if (!matched && looksLikeATask(line)) {
                candidates.add(Todo(
                    id = UUID.randomUUID().toString(),
                    title = cleanTodoTitle(line),
                    description = "",
                    isCompleted = false,
                    priority = 0,
                    dueDate = null,
                    createdAt = Date(),
                    updatedAt = Date(),
                    noteId = ""
                ))
            }
        }
        
        return candidates
    }
    
    /**
     * Applies de-duplication and merging strategy to a list of todos
     */
    fun deduplicateAndMerge(todos: List<Todo>): List<Todo> {
        val groupedTuples = todos.groupBy { normalizeForComparison(it.title) }
        
        return groupedTuples.values.map { group ->
            // Select the highest priority among duplicates
            val maxPriority = group.maxOf { it.priority }
            
            // Use the longest title as it might contain more detail
            val representative = group.maxByOrNull { it.title.length } ?: group.first()
            
            // Merge descriptions if available
            val mergedDescription = group.joinToString("\n") { it.description }.trim()
            
            // Use earliest due date if multiple exist
            val earliestDueDate = group.filter { it.dueDate != null }
                .minByOrNull { it.dueDate!! }
                ?.dueDate
            
            representative.copy(
                id = UUID.randomUUID().toString(), // Generate new ID for merged item
                priority = maxPriority,
                description = if (mergedDescription.isNotEmpty()) mergedDescription else representative.description,
                dueDate = earliestDueDate ?: representative.dueDate
            )
        }
    }
    
    /**
     * Determines priority level based on urgency keywords
     */
    private fun determinePriority(title: String): Int {
        val highUrgencyKeywords = listOf("紧急", "立刻", "马上", "尽快", "urgent", "asap", "immediately")
        val mediumUrgencyKeywords = listOf("今天", "本周", "这周", "today", "week", "soon")
        
        val lowerCaseTitle = title.lowercase()
        
        for (keyword in highUrgencyKeywords) {
            if (lowerCaseTitle.contains(keyword.lowercase())) {
                return 2 // High priority
            }
        }
        
        for (keyword in mediumUrgencyKeywords) {
            if (lowerCaseTitle.contains(keyword.lowercase())) {
                return 1 // Medium priority
            }
        }
        
        return 0 // Low priority
    }
    
    /**
     * Attempts to extract a due date from the text
     */
    private fun extractDueDate(title: String): String? {
        // Look for dates in various formats
        val datePatterns = listOf(
            Regex("""(\d{4})[年/-](\d{1,2})[月/-](\d{1,2})[日]?"""),
            Regex("""(\d{1,2})[月/-](\d{1,2})[日]?"""),
            Regex("""(今天|明天|后天|大后天|本周|下周|本月|下月)""")
        )
        
        for (pattern in datePatterns) {
            val match = pattern.find(title)
            if (match != null) {
                return match.value
            }
        }
        
        return null
    }
    
    /**
     * Cleans up a todo title by removing prefixes and normalizing
     */
    private fun cleanTodoTitle(title: String): String {
        var cleaned = title
        
        // Remove common prefixes
        val prefixes = listOf("需要", "要", "计划", "提醒", "记得", "别忘了", "截止到?", "请", "应该", "必须")
        for (prefix in prefixes) {
            if (cleaned.startsWith(prefix)) {
                cleaned = cleaned.substring(prefix.length).trim()
                break
            }
        }
        
        // Clean up any remaining punctuation
        cleaned = cleaned.trim(':', '：', ',', '，', '.', '。', ';', '；').trim()
        
        return cleaned
    }
    
    /**
     * Checks if a string looks like a task/todo
     */
    private fun looksLikeATask(text: String): Boolean {
        val trimmed = text.trim()
        if (trimmed.length < 3) return false
        
        // Check for imperative verbs or task-like structures
        val taskIndicators = listOf(
