    /**
     * Normalizes a string for comparison purposes (removing extra spaces, case-insensitive)
     */
    private fun normalizeForComparison(str: String): String {
        return str.lowercase().replace(Regex("\\s+"), "").replace(Regex("[\\p{Punct}\\s]+"), "")
    }
